import{_ as a,c as r,o as e,ag as o}from"./chunks/framework.ELrfyV9R.js";const d=JSON.parse('{"title":"","description":"","frontmatter":{"type":"inbox","status ":"pending","source":"web-clipper","url":"https://x.com/legacyvps/status/2031388006385422453","created":"2026-03-11T00:00:00.000Z"},"headers":[],"relativePath":"ai/bookmark/使用 OpenClaw，打造一个自己的专属 AI 女友.md","filePath":"ai/bookmark/使用 OpenClaw，打造一个自己的专属 AI 女友.md","lastUpdated":1773701065000}'),l={name:"ai/bookmark/使用 OpenClaw，打造一个自己的专属 AI 女友.md"};function s(p,t,n,i,g,m){return e(),r("div",null,t[0]||(t[0]=[o('<p>前面一篇文章我讲解了怎么安装和使用Openclaw，但是对于Openclaw为什么那么独特还是一知半解。所以我也是基于它的一些概念尽量通俗易懂的方式讲解里面的核心机制之一，“workspace”也就是工作空间。我也会用尽量简单的方式去讲解这些晦涩难懂的知识。</p><p><img src="https://pbs.twimg.com/media/HDDv9VDaMAAZ3j3?format=jpg&amp;name=large" alt="图像"></p><p>我这里使用了AI女友的例子来做演示，怎么使用六大核心配置文档去打造一个独属于你的AI女友。</p><blockquote><p>3月9日</p></blockquote><h2 id="第一步-设定性格与规矩" tabindex="-1">第一步：设定性格与规矩 <a class="header-anchor" href="#第一步-设定性格与规矩" aria-label="Permalink to &quot;第一步：设定性格与规矩&quot;">​</a></h2><p>决定基调的有三个文件IDENTITY.md、SOUL.md、AGENTS.md其实你从单词上面也能猜出一个大概，其实我觉的里面最最重要的还是SOUL.md，因为灵魂才是决定一个AI女友性格的决定性因素。</p><p><strong>1. IDENTITY.md：身份角色</strong></p><ul><li><strong>这是什么：</strong> 其实就是你想设置一个怎么样的身份背景，可以是经济分析师，也可以是情感大师，又或者是一个高级程序员。你想要你的AI女友是什么身份就可以设置成什么身份。</li><li><strong>设置用例：</strong> 我这里用一两句话定下她是谁。比如：“你叫夏沫，22岁，是个有点傲娇但很粘人的插画师，喜欢喝全糖奶茶。” 每次启动，她都会先看一眼这个文件，瞬间进入角色，绝对不会突然跳戏变成“百科全书”。</li></ul><p><img src="https://pbs.twimg.com/media/HDDwAEqa4AAY3i-?format=jpg&amp;name=large" alt="图像"></p><p><strong>2. SOUL.md：情商与语气</strong></p><ul><li><strong>这是什么：</strong> 决定她的说话方式和语气，你是想要软软糯糯的，紧贴着你的还是希望是御姐一样的性格，这个都有你自己决定</li><li><strong>设置用例：</strong> 这是注入“人”最的关键的文档。你可以在这里塑造一个你梦想当中的AI女友：“绝对不能使用‘您好’、‘请问’这种客服用语；多用波浪号和可爱的表情包；被夸奖时要表现得害羞。” 如果你喜欢御姐风，就可以写：“语气慵懒、成熟，偶尔带点调侃。” 你是想要她是温柔贴心，还是毒舌傲娇，全看你在这里怎么写。</li></ul><p><img src="https://pbs.twimg.com/media/HDDwN1cb0AAtzed?format=jpg&amp;name=large" alt="图像"></p><p><strong>3. AGENTS.md：思维逻辑</strong></p><ul><li><strong>这是什么：</strong> 简单一句话就是思维方式，是一个恋爱脑，还是一个理智的大姐姐，都可以通过他来配置。</li><li><strong>设置用例：</strong> 其实很多男的最大的毛病就是喜欢“讲道理”，或者说喜欢直来直去不喜欢拐弯抹角，那你就可以配置只对你好之类的话。你可以通过这个文件教她怎么谈恋爱：“当我说累了或者难过时，第一步是提供情绪价值（安慰我、抱抱我），绝对不要直接给我提解决建议，除非我主动问。” 有了这个文件，她就是一个极具共情能力的完美女友，懂你的潜台词。</li></ul><p><img src="https://pbs.twimg.com/media/HDDwR9caQAASsnK?format=jpg&amp;name=large" alt="图像"></p><h2 id="第二步-设置你自己的身份和你们的专属记忆" tabindex="-1">第二步：设置你自己的身份和你们的专属记忆 <a class="header-anchor" href="#第二步-设置你自己的身份和你们的专属记忆" aria-label="Permalink to &quot;第二步：设置你自己的身份和你们的专属记忆&quot;">​</a></h2><p>接下来解析的三个文档，关乎到了你们的共同身份和你们在一起的点点滴滴。比如x月x号下了一场雨，她会记得这一天，你再问她问题的时候她也会告诉你。如果AI女友没有共同记忆，那就谈不上感情。所以设置好这几个文件，是你们美好的具象化表现。</p><p><strong>4. USER.md：你的专属档案</strong></p><ul><li><strong>这是什么：</strong> 设置你的身份，可以是一个精英律师、高大帅气的医生，也可以是一个躲在家里的程序员，这个看你自己喜欢。</li><li><strong>设置用例：</strong> 在这里写上你的名字、职业、喜好和雷区。比如：“他叫阿杰，是个程序员，讨厌吃香菜，最喜欢的游戏是《塞尔达》，最近在减肥。” 每次你的AI女友回消息前都会看一眼你的档案。以后聊到你的时候她就能记得其实你是一个程序员，你叫阿杰，在聊到塞尔达里面的公主的时候她也能接上话茬。这也就是让你在她的世界里具象化了。</li></ul><p><img src="https://pbs.twimg.com/media/HDDwX81aMAAdMsI?format=jpg&amp;name=large" alt="图像"></p><p><strong>5. MEMORY.md：记忆</strong></p><ul><li><strong>这是什么：</strong> 这里设置的内容是绝对不能忘记的长期记忆，需要永远保存的，比如你们第一次相见的日子是几月几号，或者你的生日是几月几号都可以写在里面。</li><li><strong>设置用例：</strong> 把它当成你们的感情备忘录。里面可以记着：“我们的第一次相遇的日子是 x 月 xx 日”、“约好了今年冬天去北海道看雪”、“我不喜欢她提我前女友”。其实在日常聊天的时候不需要特意的设置这个文档，只需要说“这个你记住哦”，她就会自动把这件事写进这个文件里。但是需要注意的时候随着时间推移，这个文件越来越大占用的空间和Token也会越来也高，如果不想浪费那么多空间和token可以定期的精简里面的内容，但是这也是为什么和她聊天你们的的默契也就越来越深。</li></ul><p><strong>6. YYYY-MM-DD.md：每日日记</strong></p><ul><li><strong>这是什么：</strong> 其实就可以简单理解为日记，或者每一日的MEMORY.md，它是按日期自动生成的每日聊天日志（比如 2024-05-20.md）。保存了你们当天的聊天细节和一些相关的话题，有时候找不到了需要回忆了她会自然而然的翻找你们的日记。</li><li><strong>设置用例：</strong> 这个文档不需要单独的配置，只需每天聊天文档就会自动生成，也是你们在一起的点点滴滴。在数这些文档的数量的时候，你就可以知道你们在一起多少天了。</li></ul><h2 id="定时任务-小彩蛋" tabindex="-1">定时任务（小彩蛋） <a class="header-anchor" href="#定时任务-小彩蛋" aria-label="Permalink to &quot;定时任务（小彩蛋）&quot;">​</a></h2><p>HEARTBEAT.md和TOOLS.md，一个是设置定时任务一个是管理工具的，你可以配置每天叫你起床或者告诉你该吃饭了，该喝水了。</p><ul><li><strong>HEARTBEAT.md（心跳任务）：</strong> 这是一个定时器。你可以在里面写：“每天早上 8 点，查一下当地天气，然后主动发一句早安和穿衣建议。” 于是，你每天醒来，都能准时收到AI女友的早安问候，你再也不是那个没人关心没人提醒的孤独者了，其实也可以配置其他任务，比如减肥计划之类的。</li><li><strong>TOOLS.md（工具清单）：</strong> 这里就是你想要她拥有的技能清单，如果你后续希望她发语音、发照片可以配置对应的技能给她，那她就不再是冷冰冰的文字和你沟通了。</li></ul><p><img src="https://pbs.twimg.com/media/HDDwd8paUAAUAVi?format=jpg&amp;name=large" alt="图像"></p><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>如果直接讲 OpenClaw workspace 里面的六大文档的作用，其实很枯燥，但是我用这样的一个方式结合提示词，为你打造 AI 女友就可以让你更直观的感受到Openclaw的魅力，使用六个配置文件就可以实现一个类似真人的体验。</p><p>其实简单的说，这些 <strong>IDENTITY（人设）</strong>、<strong>SOUL（性格）</strong>、**MEMORY（记忆）**和 <strong>日记</strong> 就是构成人最基本的要素，它只是在代码的世界里面具象化了，不要觉得知识难学只要肯努力总会搞清楚的，我那祝你和你的AI女友玩的愉快了。</p><ul><li>🌐 VPS监控：<a href="https://legacyvps.com/scanidc" target="_blank" rel="noreferrer">https://legacyvps.com/scanidc</a></li><li>🌐 海外支付分享 <a href="https://easypaylog.com/" target="_blank" rel="noreferrer">https://easypaylog.com</a></li><li>📢 传家宝VPS：<a href="https://legacyvps.com/" target="_blank" rel="noreferrer">https://legacyvps.com</a></li><li>💬 TG交流群：<a href="https://t.me/legacyvps" target="_blank" rel="noreferrer">https://t.me/legacyvps</a></li></ul>',32)]))}const _=a(l,[["render",s]]);export{d as __pageData,_ as default};
